# geometry.spy - Geometric utilities

from shapes import IDrawable, IMeasurable, Rectangle, Circle

class Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return (dx * dx + dy * dy) ** 0.5

    @override
    def __str__(self) -> str:
        return f"({self.x}, {self.y})"

def measure_shape(shape: IMeasurable) -> tuple[float, float]:
    return (shape.get_area(), shape.get_perimeter())

def compare_shapes(s1: IMeasurable, s2: IMeasurable) -> str:
    a1: float = s1.get_area()
    a2: float = s2.get_area()
    if a1 > a2:
        return "first"
    elif a2 > a1:
        return "second"
    return "equal"

class ShapeCollection:
    items: list[IDrawable]

    def __init__(self):
        self.items = []

    def add(self, shape: IDrawable) -> None:
        self.items.append(shape)

    def draw_all(self) -> list[str]:
        result: list[str] = []
        for s in self.items:
            result.append(s.draw())
        return result
